#!/usr/bin/env node
'use strict';

/**
 * Download missing LDraw .dat parts from library.ldraw.org into ldraw_parts/.
 * Usage: node scripts/download-ldraw-parts.js [part1.dat part2.dat ...]
 * Or: node scripts/download-ldraw-parts.js --list scripts/missing-dsh-parts.txt
 *
 * Parts that are generated by the viewer (e.g. stud10.dat) are skipped.
 */

const https = require('https');
const fs = require('fs');
const path = require('path');

const BASE = 'https://library.ldraw.org/library/official';
const OUT_DIR = path.join(__dirname, '..', 'ldraw_parts');

// Generated by the app – do not download
const GENERATED = new Set(['stud10.dat', 'stud6.dat', 'stud6a.dat', 'stud13.dat', 'stud15.dat', 'stud17.dat', 'stud17a.dat', 'studel.dat', 'studp01.dat', 'studa.dat', 'stud.dat']);

function get(url) {
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      if (res.statusCode === 200) {
        const chunks = [];
        res.on('data', (c) => chunks.push(c));
        res.on('end', () => resolve(Buffer.concat(chunks).toString('utf8')));
      } else {
        resolve(null);
      }
    }).on('error', reject);
  });
}

function candidates(id) {
  const lower = id.toLowerCase();
  const list = [];
  if (lower.includes('/')) {
    const [pre, name] = lower.split('/');
    if (pre === '48' || pre === '8') list.push(`${BASE}/p/${pre}/${name}`);
    if (pre === 's') list.push(`${BASE}/parts/s/${name}`);
    list.push(`${BASE}/parts/${lower}`);
  } else {
    list.push(`${BASE}/parts/${lower}`);
    list.push(`${BASE}/parts/s/${lower}`);
    list.push(`${BASE}/p/${lower}`);
    list.push(`${BASE}/p/48/${lower}`);
    list.push(`${BASE}/p/8/${lower}`);
  }
  return list;
}

async function downloadOne(id) {
  const lower = id.toLowerCase().replace(/\.dat$/i, '') + '.dat';
  if (GENERATED.has(lower)) {
    console.log('Skip (generated): ' + lower);
    return { id: lower, ok: true, skipped: true };
  }
  const urls = candidates(lower);
  for (const url of urls) {
    const body = await get(url);
    if (body) {
      const outPath = path.join(OUT_DIR, lower);
      const dir = path.dirname(outPath);
      if (dir !== OUT_DIR) {
        try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
      }
      fs.writeFileSync(outPath, body, 'utf8');
      console.log('OK: ' + lower + ' -> ' + outPath);
      return { id: lower, ok: true };
    }
  }
  console.warn('Not found: ' + lower);
  return { id: lower, ok: false };
}

async function main() {
  let parts = [];
  const args = process.argv.slice(2);
  if (args[0] === '--list' && args[1]) {
    const listPath = path.resolve(args[1]);
    if (fs.existsSync(listPath)) {
      parts = fs.readFileSync(listPath, 'utf8')
        .split(/\n/)
        .map((l) => l.trim().toLowerCase())
        .filter((l) => l && !l.startsWith('#'))
        .map((l) => l.endsWith('.dat') ? l : l + '.dat');
    }
  } else {
    parts = args.map((a) => a.endsWith('.dat') ? a : a + '.dat');
  }
  if (parts.length === 0) {
    parts = [
      '3713.dat', '3648b.dat', '4716.dat', '10928.dat', '3005.dat', '3666.dat',
      '74611.dat', '4150.dat', '27925.dat', '79393.dat', '27507.dat', '43093.dat',
      '18654.dat', '3749.dat', '11478.dat', '3069b.dat', '5090.dat', '3832.dat',
      '3034.dat', '44728.dat', '5092.dat', '5091.dat', '4162.dat', '11211.dat'
    ];
    console.log('Using default list of parts reported missing for DSH.ldr');
  }
  try { fs.mkdirSync(OUT_DIR, { recursive: true }); } catch (e) {}
  let ok = 0, fail = 0;
  for (const id of parts) {
    const r = await downloadOne(id);
    if (r.ok && !r.skipped) ok++;
    else if (!r.skipped) fail++;
  }
  console.log('Done: ' + ok + ' downloaded, ' + fail + ' not found.');
}

main().catch((e) => { console.error(e); process.exit(1); });
